    n := len(s)
    dp := make([]int, n+1)
    dp[0], dp[1] = 1, 1
    for i := 2; i <= n; i++ {
        if s[i-1] != '0' { dp[i] += dp[i-1] }
        twoDigit, _ := strconv.Atoi(s[i-2 : i])
        if twoDigit >= 10 && twoDigit <= 26 { dp[i] += dp[i-2] }
    }
    return dp[n]
}

