public List<List<String>> accountsMerge(List<List<String>> accounts) {
    int n = accounts.size();
    int[] parent = new int[n];
    for (int i = 0; i < n; i++) parent[i] = i;
    Map<String, Integer> emailToAcct = new HashMap<>();
    for (int i = 0; i < n; i++) {
        for (int j = 1; j < accounts.get(i).size(); j++) {
            String email = accounts.get(i).get(j);
            if (emailToAcct.containsKey(email)) {
                union(parent, i, emailToAcct.get(email));
            } else {
                emailToAcct.put(email, i);
            }
        }
    }
    Map<Integer, TreeSet<String>> groups = new HashMap<>();
    for (var entry : emailToAcct.entrySet()) {
        int root = find(parent, entry.getValue());
        groups.computeIfAbsent(root, k -> new TreeSet<>()).add(entry.getKey());
    }
    List<List<String>> result = new ArrayList<>();
    for (var entry : groups.entrySet()) {
        List<String> merged = new ArrayList<>();
        merged.add(accounts.get(entry.getKey()).get(0));
        merged.addAll(entry.getValue());
        result.add(merged);
    }
    return result;
