public List<String> findWords(char[][] board, String[] words) {
    Map<String, Object> root = new HashMap<>();
    for (String word : words) {
        Map<String, Object> node = root;
        for (char c : word.toCharArray()) {
            node = (Map<String, Object>) node.computeIfAbsent(String.valueOf(c), k -> new HashMap<>());
        }
        node.put("#", word);
    }
    List<String> result = new ArrayList<>();
    int rows = board.length, cols = board[0].length;
    dfsFindWords(board, 0, 0, root, result, rows, cols);
    for (int r = 0; r < rows; r++)
        for (int c = 0; c < cols; c++)
            dfsFindWords(board, r, c, root, result, rows, cols);
    return result;
}
private void dfsFindWords(char[][] board, int r, int c, Map<String, Object> node, List<String> result, int rows, int cols) {
    if (r < 0 || r >= rows || c < 0 || c >= cols || board[r][c] == '*') return;
    String key = String.valueOf(board[r][c]);
    if (!node.containsKey(key)) return;
    Map<String, Object> nxt = (Map<String, Object>) node.get(key);
    if (nxt.containsKey("#")) {
        result.add((String) nxt.remove("#"));
    }
    char temp = board[r][c];
    board[r][c] = '*';
    dfsFindWords(board, r+1, c, nxt, result, rows, cols);
    dfsFindWords(board, r-1, c, nxt, result, rows, cols);
    dfsFindWords(board, r, c+1, nxt, result, rows, cols);
    dfsFindWords(board, r, c-1, nxt, result, rows, cols);
    board[r][c] = temp;
}

