struct TrieNode {
    unordered_map<char, TrieNode*> children;
    string word = "";
};
void dfsFindWords(vector<vector<char>>& board, int r, int c, TrieNode* node, vector<string>& result) {
    if (r < 0 || r >= board.size() || c < 0 || c >= board[0].size() || board[r][c] == '*') return;
    char ch = board[r][c];
    if (!node->children.count(ch)) return;
    TrieNode* nxt = node->children[ch];
    if (!nxt->word.empty()) {
        result.push_back(nxt->word);
        nxt->word = "";
    }
    board[r][c] = '*';
    dfsFindWords(board, r+1, c, nxt, result);
    dfsFindWords(board, r-1, c, nxt, result);
    dfsFindWords(board, r, c+1, nxt, result);
    dfsFindWords(board, r, c-1, nxt, result);
    board[r][c] = ch;
}
vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {
    TrieNode* root = new TrieNode();
    for (auto& word : words) {
        TrieNode* node = root;
        for (char c : word) {
            if (!node->children.count(c)) node->children[c] = new TrieNode();
            node = node->children[c];
        }
        node->word = word;
    }
    vector<string> result;
    for (int r = 0; r < board.size(); r++)
        for (int c = 0; c < board[0].size(); c++)
            dfsFindWords(board, r, c, root, result);
    return result;
}

