type TrieNode struct {
    children map[byte]*TrieNode
    word     string
}
func newTrieNode() *TrieNode { return &TrieNode{children: make(map[byte]*TrieNode)} }
func findWords(board [][]byte, words []string) []string {
    root := newTrieNode()
    for _, word := range words {
        node := root
        for i := 0; i < len(word); i++ {
            c := word[i]
            if node.children[c] == nil { node.children[c] = newTrieNode() }
            node = node.children[c]
        }
        node.word = word
    }
    rows, cols := len(board), len(board[0])
    result := []string{}
    var dfs func(r, c int, node *TrieNode)
    dfs = func(r, c int, node *TrieNode) {
        if r < 0 || r >= rows || c < 0 || c >= cols || board[r][c] == '*' { return }
        ch := board[r][c]
        nxt := node.children[ch]
        if nxt == nil { return }
        if nxt.word != "" {
            result = append(result, nxt.word)
            nxt.word = ""
        }
        board[r][c] = '*'
        dfs(r+1, c, nxt); dfs(r-1, c, nxt); dfs(r, c+1, nxt); dfs(r, c-1, nxt)
        board[r][c] = ch
    }
    for r := 0; r < rows; r++ {
        for c := 0; c < cols; c++ {
            dfs(r, c, root)
        }
    }
    return result
}

