class WordDictionary {
    private Map<String, Object> root = new HashMap<>();

    public void addWord(String word) {
        Map<String, Object> node = root;
        for (char c : word.toCharArray()) {
            node = (Map<String, Object>) node.computeIfAbsent(String.valueOf(c), k -> new HashMap<>());
        }
        node.put("#", true);
    }
    public boolean search(String word) {
        return dfs(root, word, 0);
    }
    private boolean dfs(Map<String, Object> node, String word, int i) {
        if (i == word.length()) return node.containsKey("#");
        char c = word.charAt(i);
        if (c == '.') {
            for (String key : node.keySet()) {
                if (!key.equals("#") && dfs((Map<String, Object>) node.get(key), word, i + 1)) return true;
            }
            return false;
        }
        if (!node.containsKey(String.valueOf(c))) return false;
        return dfs((Map<String, Object>) node.get(String.valueOf(c)), word, i + 1);
    }
}

