  private root: any = {};

  addWord(word: string): void {
    let node = this.root;
    for (const c of word) node = node[c] = node[c] || {};
    node['#'] = true;
  }
  search(word: string): boolean {
    function dfs(node: any, i: number): boolean {
      if (i === word.length) return '#' in node;
      const c = word[i];
      if (c === '.') {
        return Object.keys(node).some(k => k !== '#' && dfs(node[k], i + 1));
      }
      if (!(c in node)) return false;
      return dfs(node[c], i + 1);
    }
    return dfs(this.root, 0);
  }
}

