class WordDictionary {
    struct Node {
        unordered_map<char, Node*> children;
        bool isEnd = false;
    };
    Node* root;
    bool dfs(Node* node, const string& word, int i) {
        if (i == word.size()) return node->isEnd;
        char c = word[i];
        if (c == '.') {
            for (auto& [k, child] : node->children) {
                if (dfs(child, word, i + 1)) return true;
            }
            return false;
        }
        if (!node->children.count(c)) return false;
        return dfs(node->children[c], word, i + 1);
    }
public:
    WordDictionary() { root = new Node(); }
    void addWord(string word) {
        Node* node = root;
        for (char c : word) {
            if (!node->children.count(c)) node->children[c] = new Node();
            node = node->children[c];
        }
        node->isEnd = true;
    }
    bool search(string word) {
        return dfs(root, word, 0);
    }
};

