def game_of_life(board):
    rows, cols = len(board), len(board[0])
    def count_live_neighbors(r, c):
        count = 0
        for dr in (-1, 0, 1):
            for dc in (-1, 0, 1):
                if dr == 0 and dc == 0:
                    continue
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and board[nr][nc] in (1, -1):
                    count += 1
        return count
    for r in range(rows):
        for c in range(cols):
            live = count_live_neighbors(r, c)
            if board[r][c] == 1 and (live < 2 or live > 3):
                board[r][c] = -1
            elif board[r][c] == 0 and live == 3:
                board[r][c] = 2
    for r in range(rows):
        for c in range(cols):
            if board[r][c] == -1:
                board[r][c] = 0
            elif board[r][c] == 2:
                board[r][c] = 1

