def find_anagrams(s, p):
    if len(p) > len(s):
        return []
    need = [0] * 26
    window = [0] * 26
    for c in p:
        need[ord(c) - ord('a')] += 1
    result = []
    for i in range(len(s)):
        window[ord(s[i]) - ord('a')] += 1
        if i >= len(p):
