    items.sort((a, b) => b[1] - a[1]);
    const [c, freq] = items[0];
    if (result.length && result[result.length - 1] === c) return '';
    result.push(c);
    if (freq - 1 > 0) items[0] = [c, freq - 1]; else items.shift();
  }
