public int nthUglyNumber(int n) {
    PriorityQueue<Long> heap = new PriorityQueue<>();
    Set<Long> seen = new HashSet<>();
    heap.offer(1L);
    seen.add(1L);
    long val = 1;
    int[] factors = {2, 3, 5};
    for (int i = 0; i < n; i++) {
        val = heap.poll();
        for (int factor : factors) {
            long next = val * factor;
            if (seen.add(next)) heap.offer(next);
        }
    }
    return (int) val;
}

