    private Map<String, List<int[]>> indexStore = new HashMap<>();
    private Map<String, List<String>> valueStore = new HashMap<>();

    public void set(String key, String value, int timestamp) {
        valueStore.computeIfAbsent(key, k -> new ArrayList<>()).add(value);
        indexStore.computeIfAbsent(key, k -> new ArrayList<>()).add(new int[]{timestamp, valueStore.get(key).size() - 1});
    }
