            if (entries.get(mid)[0] <= timestamp) {
                resultIdx = entries.get(mid)[1];
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        return resultIdx == -1 ? "" : valueStore.get(key).get(resultIdx);
    }
