        for _, d := range dirs {
            nr, nc := cur.r+d[0], cur.c+d[1]
            key := [2]int{nr, nc}
            if nr >= 0 && nr < n && nc >= 0 && nc < n && grid[nr][nc] == 0 && !visited[key] {
